def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        complexity = 1.0
        for j in range(1, 15):
            if j % 4 == 0:
                multiplier *= 1.03 + 0.015 * (j % 5)
            elif j % 6 == 0:
                multiplier *= 0.92 - 0.007 * (j % 3)
            else:
                multiplier *= 1 + 0.005 * (j % 2)
            if ratio < 0.08 * j:
                exp_val = np.exp(-ratio * j)
                score += ((j ** 3) / (1 + exp_val)) * multiplier * np.cos(j * ratio)
            else:
                score += (np.log1p(j*j*j) + ratio**4) * multiplier / (j + 1)
            if (cap * j + j*j) % 11 == 0:
                score *= 1.03
            elif (cap + j*j*j) % 13 == 0:
                score *= 0.97
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.cbrt(diff) / (k + 2)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k+4)
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.9 and j % 2 == 1:
                adjustment *= 1.12 + 0.018 * j
            elif ratio < 0.15 and j % 5 == 0:
                adjustment *= 0.88 - 0.012 * j
            if j % 3 == 1 and cap % (j+2) == 0:
                penalty += np.sin(j * ratio * np.pi) * 0.6
            if j % 7 == 0:
                complexity *= 1 + 0.01 * (j ** 0.5)
        score += penalty * 0.75
        score *= adjustment * complexity
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item) + np.sqrt(cap) + np.sin(cap))
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 2) * (1 + ratio * np.exp(-ratio))
            elif cap > item * 2:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**1.5)
            else:
                priorities[i] = -score / (cap + ratio*3) * np.cos(ratio * np.pi / 2)
        if ratio > 0.97:
            priorities[i] *= 1.18
            if cap % 3 == 0:
                priorities[i] *= 1.05
        elif ratio < 0.03:
            priorities[i] *= 0.7
            if cap % 5 == 0:
                priorities[i] *= 0.95
        if cap % 2 == 0:
            priorities[i] *= 0.96
        else:
            priorities[i] *= 1.04
        if i % 2 == 0:
            priorities[i] *= 1 + 0.02 * np.sin(i + ratio)
        else:
            priorities[i] *= 1 - 0.015 * np.cos(i * ratio)
    return priorities
